package store

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"strconv"
	"time"

	"github.com/redis/go-redis/v9"
)

// RedisStore implements Store interface using Redis.
type RedisStore struct {
	client *redis.Client
}

// NewRedisStore creates a new Redis store instance.
func NewRedisStore() (*RedisStore, error) {
	addr := os.Getenv("REDIS_ADDR")
	if addr == "" {
		addr = "localhost:6379"
	}

	password := os.Getenv("REDIS_PASSWORD")
	passwordRequired := true
	if val := os.Getenv("REDIS_PASSWORD_REQUIRED"); val != "" {
		passwordRequired, _ = strconv.ParseBool(val)
	}

	if passwordRequired && password == "" {
		return nil, fmt.Errorf("REDIS_PASSWORD is required")
	}

	db := 0
	if val := os.Getenv("REDIS_DB"); val != "" {
		db, _ = strconv.Atoi(val)
	}

	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       db,
	})

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := client.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("failed to connect to Redis: %w", err)
	}

	return &RedisStore{client: client}, nil
}

// Ping checks connectivity to Redis.
func (r *RedisStore) Ping(ctx context.Context) error {
	return r.client.Ping(ctx).Err()
}

// GetSandboxBySessionID retrieves sandbox info by session ID.
func (r *RedisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	key := sessionKey(sessionID)
	data, err := r.client.Get(ctx, key).Result()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, fmt.Errorf("failed to get session: %w", err)
	}

	var sandbox SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, fmt.Errorf("%w: %v", ErrInvalidSession, err)
	}

	return &sandbox, nil
}

// StoreSandbox stores sandbox info atomically using pipeline.
func (r *RedisStore) StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	key := sessionKey(sandbox.SessionID)
	ttl := time.Until(sandbox.ExpiresAt)
	if ttl <= 0 {
		ttl = DefaultSessionTTL
	}

	pipe := r.client.Pipeline()
	pipe.Set(ctx, key, data, ttl)
	pipe.ZAdd(ctx, SessionExpiryZSet, redis.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	})
	pipe.ZAdd(ctx, SessionActivityZSet, redis.Z{
		Score:  float64(sandbox.LastActivityAt.Unix()),
		Member: sandbox.SessionID,
	})

	_, err = pipe.Exec(ctx)
	if err != nil {
		return fmt.Errorf("failed to store sandbox: %w", err)
	}

	return nil
}

// UpdateSandbox updates existing sandbox info.
func (r *RedisStore) UpdateSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	// Check if session exists
	key := sessionKey(sandbox.SessionID)
	exists, err := r.client.Exists(ctx, key).Result()
	if err != nil {
		return fmt.Errorf("failed to check session existence: %w", err)
	}
	if exists == 0 {
		return ErrNotFound
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	ttl := time.Until(sandbox.ExpiresAt)
	if ttl <= 0 {
		ttl = DefaultSessionTTL
	}

	pipe := r.client.Pipeline()
	pipe.Set(ctx, key, data, ttl)
	pipe.ZAdd(ctx, SessionExpiryZSet, redis.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	})
	pipe.ZAdd(ctx, SessionActivityZSet, redis.Z{
		Score:  float64(sandbox.LastActivityAt.Unix()),
		Member: sandbox.SessionID,
	})

	_, err = pipe.Exec(ctx)
	if err != nil {
		return fmt.Errorf("failed to update sandbox: %w", err)
	}

	return nil
}

// DeleteSandboxBySessionID removes a sandbox from the store.
func (r *RedisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKey(sessionID)

	pipe := r.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, SessionExpiryZSet, sessionID)
	pipe.ZRem(ctx, SessionActivityZSet, sessionID)

	_, err := pipe.Exec(ctx)
	if err != nil {
		return fmt.Errorf("failed to delete sandbox: %w", err)
	}

	return nil
}

// ListExpiredSandboxes returns sessions that expired before the given time.
func (r *RedisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	if limit <= 0 {
		limit = 100
	}

	results, err := r.client.ZRangeByScore(ctx, SessionExpiryZSet, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: int64(limit),
	}).Result()

	if err != nil {
		return nil, fmt.Errorf("failed to list expired sandboxes: %w", err)
	}

	// Clean up orphaned ZSET entries
	for _, sessionID := range results {
		key := sessionKey(sessionID)
		exists, err := r.client.Exists(ctx, key).Result()
		if err != nil {
			continue
		}
		if exists == 0 {
			// Orphaned entry, remove from ZSETs
			r.client.ZRem(ctx, SessionExpiryZSet, sessionID)
			r.client.ZRem(ctx, SessionActivityZSet, sessionID)
		}
	}

	return results, nil
}

// ListInactiveSandboxes returns sessions inactive before the given time.
func (r *RedisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	if limit <= 0 {
		limit = 100
	}

	results, err := r.client.ZRangeByScore(ctx, SessionActivityZSet, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: int64(limit),
	}).Result()

	if err != nil {
		return nil, fmt.Errorf("failed to list inactive sandboxes: %w", err)
	}

	return results, nil
}

// UpdateSessionLastActivity updates the last activity timestamp.
func (r *RedisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	key := sessionKey(sessionID)

	// Get existing session
	data, err := r.client.Get(ctx, key).Result()
	if err == redis.Nil {
		return ErrNotFound
	}
	if err != nil {
		return fmt.Errorf("failed to get session: %w", err)
	}

	var sandbox SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return fmt.Errorf("%w: %v", ErrInvalidSession, err)
	}

	sandbox.LastActivityAt = at

	// Update session and activity index
	newData, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	ttl := time.Until(sandbox.ExpiresAt)
	if ttl <= 0 {
		ttl = DefaultSessionTTL
	}

	pipe := r.client.Pipeline()
	pipe.Set(ctx, key, newData, ttl)
	pipe.ZAdd(ctx, SessionActivityZSet, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	})

	_, err = pipe.Exec(ctx)
	if err != nil {
		return fmt.Errorf("failed to update activity: %w", err)
	}

	return nil
}

// Close closes the Redis connection.
func (r *RedisStore) Close() error {
	return r.client.Close()
}

// Package store provides session storage backends for AgentCube.
// It supports both Redis and Valkey implementations with a unified interface.
package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"sync"
	"time"
)

// ErrNotFound is returned when a session is not found in the store.
var ErrNotFound = errors.New("session not found")

// ErrInvalidSession is returned when session data is corrupted or invalid.
var ErrInvalidSession = errors.New("invalid session data")

// Store defines the interface for session storage backends.
type Store interface {
	// Ping checks connectivity to the store.
	Ping(ctx context.Context) error

	// GetSandboxBySessionID retrieves sandbox info by session ID.
	GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error)

	// StoreSandbox stores sandbox info atomically.
	StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error

	// UpdateSandbox updates existing sandbox info.
	UpdateSandbox(ctx context.Context, sandbox *SandboxInfo) error

	// DeleteSandboxBySessionID removes a sandbox from the store.
	DeleteSandboxBySessionID(ctx context.Context, sessionID string) error

	// ListExpiredSandboxes returns sessions that expired before the given time.
	ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error)

	// ListInactiveSandboxes returns sessions inactive before the given time.
	ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error)

	// UpdateSessionLastActivity updates the last activity timestamp.
	UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error

	// Close closes the store connection.
	Close() error
}

// SandboxInfo represents a sandbox session stored in the backend.
type SandboxInfo struct {
	SessionID        string            `json:"session_id"`
	Namespace        string            `json:"namespace"`
	Name             string            `json:"name"`
	Kind             string            `json:"kind"`
	PodIP            string            `json:"pod_ip"`
	EntryPoints      []EntryPoint      `json:"entry_points"`
	ExpiresAt        time.Time         `json:"expires_at"`
	LastActivityAt   time.Time         `json:"last_activity_at"`
	CreatedAt        time.Time         `json:"created_at"`
	Labels           map[string]string `json:"labels,omitempty"`
	Annotations      map[string]string `json:"annotations,omitempty"`
}

// EntryPoint represents a service endpoint for a sandbox.
type EntryPoint struct {
	Port       int    `json:"port"`
	Protocol   string `json:"protocol"`
	PathPrefix string `json:"path_prefix"`
}

// MarshalJSON implements custom JSON marshaling for SandboxInfo.
func (s *SandboxInfo) MarshalJSON() ([]byte, error) {
	type Alias SandboxInfo
	return json.Marshal(&struct {
		*Alias
		ExpiresAt      string `json:"expires_at"`
		LastActivityAt string `json:"last_activity_at"`
		CreatedAt      string `json:"created_at"`
	}{
		Alias:          (*Alias)(s),
		ExpiresAt:      s.ExpiresAt.Format(time.RFC3339),
		LastActivityAt: s.LastActivityAt.Format(time.RFC3339),
		CreatedAt:      s.CreatedAt.Format(time.RFC3339),
	})
}

// UnmarshalJSON implements custom JSON unmarshaling for SandboxInfo.
func (s *SandboxInfo) UnmarshalJSON(data []byte) error {
	type Alias SandboxInfo
	aux := &struct {
		*Alias
		ExpiresAt      string `json:"expires_at"`
		LastActivityAt string `json:"last_activity_at"`
		CreatedAt      string `json:"created_at"`
	}{
		Alias: (*Alias)(s),
	}
	if err := json.Unmarshal(data, aux); err != nil {
		return err
	}

	var err error
	s.ExpiresAt, err = time.Parse(time.RFC3339, aux.ExpiresAt)
	if err != nil {
		return fmt.Errorf("invalid expires_at: %w", err)
	}
	s.LastActivityAt, err = time.Parse(time.RFC3339, aux.LastActivityAt)
	if err != nil {
		return fmt.Errorf("invalid last_activity_at: %w", err)
	}
	s.CreatedAt, err = time.Parse(time.RFC3339, aux.CreatedAt)
	if err != nil {
		return fmt.Errorf("invalid created_at: %w", err)
	}
	return nil
}

// Key names for Redis/Valkey storage.
const (
	SessionKeyPrefix     = "session"
	SessionExpiryZSet    = "session:expiry"
	SessionActivityZSet  = "session:last_activity"
	DefaultSessionTTL    = 24 * time.Hour
)

// sessionKey returns the Redis key for a session.
func sessionKey(sessionID string) string {
	return fmt.Sprintf("%s:%s", SessionKeyPrefix, sessionID)
}

var (
	instance Store
	once     sync.Once
	initErr  error
)

// Storage returns the singleton Store instance.
// It initializes the store based on the STORE_TYPE environment variable.
// Supported values: "redis", "valkey". Defaults to "redis".
func Storage() (Store, error) {
	once.Do(func() {
		storeType := os.Getenv("STORE_TYPE")
		if storeType == "" {
			storeType = "redis"
		}

		switch storeType {
		case "redis":
			instance, initErr = NewRedisStore()
		case "valkey":
			instance, initErr = NewValkeyStore()
		default:
			initErr = fmt.Errorf("unsupported store type: %s", storeType)
		}
	})
	return instance, initErr
}

// ResetStorage resets the singleton instance (useful for testing).
func ResetStorage() {
	if instance != nil {
		instance.Close()
	}
	instance = nil
	once = sync.Once{}
}

package store

import (
	"context"
	"crypto/tls"
	"encoding/json"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
)

// ValkeyStore implements Store interface using Valkey.
type ValkeyStore struct {
	client valkey.Client
}

// NewValkeyStore creates a new Valkey store instance.
func NewValkeyStore() (*ValkeyStore, error) {
	addrs := os.Getenv("VALKEY_ADDR")
	if addrs == "" {
		addrs = "localhost:6379"
	}
	addresses := strings.Split(addrs, ",")

	password := os.Getenv("VALKEY_PASSWORD")

	// Parse options
	disableCache := false
	if val := os.Getenv("VALKEY_DISABLE_CACHE"); val != "" {
		disableCache, _ = strconv.ParseBool(val)
	}

	forceSingle := false
	if val := os.Getenv("VALKEY_FORCE_SINGLE"); val != "" {
		forceSingle, _ = strconv.ParseBool(val)
	}

	var tlsConfig *tls.Config
	if val := os.Getenv("VALKEY_TLS"); val == "true" {
		tlsConfig = &tls.Config{
			InsecureSkipVerify: true,
		}
	}

	clientOption := valkey.ClientOption{
		InitAddress:  addresses,
		Password:     password,
		DisableCache: disableCache,
		TLSConfig:    tlsConfig,
	}

	if forceSingle || len(addresses) == 1 {
		clientOption.ForceSingleClient = true
	}

	client, err := valkey.NewClient(clientOption)
	if err != nil {
		return nil, fmt.Errorf("failed to create Valkey client: %w", err)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := client.Do(ctx, client.B().Ping().Build()).Error(); err != nil {
		return nil, fmt.Errorf("failed to connect to Valkey: %w", err)
	}

	return &ValkeyStore{client: client}, nil
}

// Ping checks connectivity to Valkey.
func (v *ValkeyStore) Ping(ctx context.Context) error {
	return v.client.Do(ctx, v.client.B().Ping().Build()).Error()
}

// GetSandboxBySessionID retrieves sandbox info by session ID.
func (v *ValkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	key := sessionKey(sessionID)
	result := v.client.Do(ctx, v.client.B().Get().Key(key).Build())

	if result.Error() != nil {
		if valkey.IsValkeyNil(result.Error()) {
			return nil, ErrNotFound
		}
		return nil, fmt.Errorf("failed to get session: %w", result.Error())
	}

	data, err := result.ToString()
	if err != nil {
		return nil, fmt.Errorf("failed to read session data: %w", err)
	}

	var sandbox SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, fmt.Errorf("%w: %v", ErrInvalidSession, err)
	}

	return &sandbox, nil
}

// StoreSandbox stores sandbox info atomically using multi/exec.
func (v *ValkeyStore) StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	key := sessionKey(sandbox.SessionID)
	ttl := time.Until(sandbox.ExpiresAt)
	if ttl <= 0 {
		ttl = DefaultSessionTTL
	}
	ttlSeconds := int64(ttl.Seconds())

	commands := []valkey.Completed{
		v.client.B().Set().Key(key).Value(string(data)).ExSeconds(ttlSeconds).Build(),
		v.client.B().Zadd().Key(SessionExpiryZSet).ScoreMember(float64(sandbox.ExpiresAt.Unix()), sandbox.SessionID).Build(),
		v.client.B().Zadd().Key(SessionActivityZSet).ScoreMember(float64(sandbox.LastActivityAt.Unix()), sandbox.SessionID).Build(),
	}

	for _, cmd := range commands {
		if err := v.client.Do(ctx, cmd).Error(); err != nil {
			return fmt.Errorf("failed to store sandbox: %w", err)
		}
	}

	return nil
}

// UpdateSandbox updates existing sandbox info.
func (v *ValkeyStore) UpdateSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	// Check if session exists
	key := sessionKey(sandbox.SessionID)
	existsResult := v.client.Do(ctx, v.client.B().Exists().Key(key).Build())
	if existsResult.Error() != nil {
		return fmt.Errorf("failed to check session existence: %w", existsResult.Error())
	}

	exists, err := existsResult.AsInt64()
	if err != nil {
		return fmt.Errorf("failed to parse exists result: %w", err)
	}
	if exists == 0 {
		return ErrNotFound
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	ttl := time.Until(sandbox.ExpiresAt)
	if ttl <= 0 {
		ttl = DefaultSessionTTL
	}
	ttlSeconds := int64(ttl.Seconds())

	commands := []valkey.Completed{
		v.client.B().Set().Key(key).Value(string(data)).ExSeconds(ttlSeconds).Build(),
		v.client.B().Zadd().Key(SessionExpiryZSet).ScoreMember(float64(sandbox.ExpiresAt.Unix()), sandbox.SessionID).Build(),
		v.client.B().Zadd().Key(SessionActivityZSet).ScoreMember(float64(sandbox.LastActivityAt.Unix()), sandbox.SessionID).Build(),
	}

	for _, cmd := range commands {
		if err := v.client.Do(ctx, cmd).Error(); err != nil {
			return fmt.Errorf("failed to update sandbox: %w", err)
		}
	}

	return nil
}

// DeleteSandboxBySessionID removes a sandbox from the store.
func (v *ValkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKey(sessionID)

	commands := []valkey.Completed{
		v.client.B().Del().Key(key).Build(),
		v.client.B().Zrem().Key(SessionExpiryZSet).Member(sessionID).Build(),
		v.client.B().Zrem().Key(SessionActivityZSet).Member(sessionID).Build(),
	}

	for _, cmd := range commands {
		if err := v.client.Do(ctx, cmd).Error(); err != nil {
			return fmt.Errorf("failed to delete sandbox: %w", err)
		}
	}

	return nil
}

// ListExpiredSandboxes returns sessions that expired before the given time.
func (v *ValkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	if limit <= 0 {
		limit = 100
	}

	result := v.client.Do(ctx, v.client.B().Zrangebyscore().Key(SessionExpiryZSet).
		Min("-inf").Max(fmt.Sprintf("%d", before.Unix())).
		Limit(0, int64(limit)).Build())

	if result.Error() != nil {
		return nil, fmt.Errorf("failed to list expired sandboxes: %w", result.Error())
	}

	results, err := result.AsStrSlice()
	if err != nil {
		return nil, fmt.Errorf("failed to parse expired sandboxes: %w", err)
	}

	// Clean up orphaned ZSET entries
	for _, sessionID := range results {
		key := sessionKey(sessionID)
		existsResult := v.client.Do(ctx, v.client.B().Exists().Key(key).Build())
		if existsResult.Error() != nil {
			continue
		}
		exists, _ := existsResult.AsInt64()
		if exists == 0 {
			// Orphaned entry, remove from ZSETs
			v.client.Do(ctx, v.client.B().Zrem().Key(SessionExpiryZSet).Member(sessionID).Build())
			v.client.Do(ctx, v.client.B().Zrem().Key(SessionActivityZSet).Member(sessionID).Build())
		}
	}

	return results, nil
}

// ListInactiveSandboxes returns sessions inactive before the given time.
func (v *ValkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	if limit <= 0 {
		limit = 100
	}

	result := v.client.Do(ctx, v.client.B().Zrangebyscore().Key(SessionActivityZSet).
		Min("-inf").Max(fmt.Sprintf("%d", before.Unix())).
		Limit(0, int64(limit)).Build())

	if result.Error() != nil {
		return nil, fmt.Errorf("failed to list inactive sandboxes: %w", result.Error())
	}

	results, err := result.AsStrSlice()
	if err != nil {
		return nil, fmt.Errorf("failed to parse inactive sandboxes: %w", err)
	}

	return results, nil
}

// UpdateSessionLastActivity updates the last activity timestamp.
func (v *ValkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	key := sessionKey(sessionID)

	// Get existing session
	result := v.client.Do(ctx, v.client.B().Get().Key(key).Build())
	if result.Error() != nil {
		if valkey.IsValkeyNil(result.Error()) {
			return ErrNotFound
		}
		return fmt.Errorf("failed to get session: %w", result.Error())
	}

	data, err := result.ToString()
	if err != nil {
		return fmt.Errorf("failed to read session data: %w", err)
	}

	var sandbox SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return fmt.Errorf("%w: %v", ErrInvalidSession, err)
	}

	sandbox.LastActivityAt = at

	// Update session and activity index
	newData, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	ttl := time.Until(sandbox.ExpiresAt)
	if ttl <= 0 {
		ttl = DefaultSessionTTL
	}
	ttlSeconds := int64(ttl.Seconds())

	commands := []valkey.Completed{
		v.client.B().Set().Key(key).Value(string(newData)).ExSeconds(ttlSeconds).Build(),
		v.client.B().Zadd().Key(SessionActivityZSet).ScoreMember(float64(at.Unix()), sessionID).Build(),
	}

	for _, cmd := range commands {
		if err := v.client.Do(ctx, cmd).Error(); err != nil {
			return fmt.Errorf("failed to update activity: %w", err)
		}
	}

	return nil
}

// Close closes the Valkey connection.
func (v *ValkeyStore) Close() error {
	v.client.Close()
	return nil
}

package store

import (
	"context"
	"encoding/json"
	"fmt"
	"testing"
