func TestValkeyStore_MockOperations(t *testing.T) {
	mockClient := NewMockValkeyClient()
	store := &TestableValkeyStore{client: mockClient}

	ctx := context.Background()
	now := time.Now().UTC()

	sandbox := &SandboxInfo{
		SessionID:      "valkey-test-1",
		Namespace:      "default",
		Name:           "test-sandbox",
		Kind:           "Sandbox",
		PodIP:          "10.0.0.1",
		ExpiresAt:      now.Add(24 * time.Hour),
		LastActivityAt: now,
		CreatedAt:      now,
		EntryPoints:    []EntryPoint{{Port: 8080, Protocol: "HTTP", PathPrefix: "/api"}},
	}

	// Test Store
	err := store.StoreSandbox(ctx, sandbox)
	require.NoError(t, err)

	// Test Get
	retrieved, err := store.GetSandboxBySessionID(ctx, "valkey-test-1")
	require.NoError(t, err)
	assert.Equal(t, sandbox.SessionID, retrieved.SessionID)

	// Test Update
	sandbox.Name = "updated-name"
	err = store.UpdateSandbox(ctx, sandbox)
	require.NoError(t, err)

	retrieved, err = store.GetSandboxBySessionID(ctx, "valkey-test-1")
	require.NoError(t, err)
	assert.Equal(t, "updated-name", retrieved.Name)

	// Test UpdateSessionLastActivity
	newActivity := now.Add(time.Hour)
	err = store.UpdateSessionLastActivity(ctx, "valkey-test-1", newActivity)
	require.NoError(t, err)

	retrieved, err = store.GetSandboxBySessionID(ctx, "valkey-test-1")
	require.NoError(t, err)
	assert.True(t, retrieved.LastActivityAt.Equal(newActivity))

	// Test ListExpired
	expired, err := store.ListExpiredSandboxes(ctx, now.Add(25*time.Hour), 100)
	require.NoError(t, err)
	assert.Len(t, expired, 1)

	// Test Delete
	err = store.DeleteSandboxBySessionID(ctx, "valkey-test-1")
	require.NoError(t, err)

	_, err = store.GetSandboxBySessionID(ctx, "valkey-test-1")
	assert.Equal(t, ErrNotFound, err)
}

