func TestValkeyStore_ConcurrentWrites(t *testing.T) {
	mockClient := NewMockValkeyClient()
	store := &TestableValkeyStore{client: mockClient}

	ctx := context.Background()
	now := time.Now().UTC()

	sandbox := &SandboxInfo{
		SessionID:      "concurrent-valkey",
		Namespace:      "default",
		Name:           "test",
		Kind:           "Sandbox",
		ExpiresAt:      now.Add(time.Hour),
		LastActivityAt: now,
		CreatedAt:      now,
	}

	// Initial store
	err := store.StoreSandbox(ctx, sandbox)
	require.NoError(t, err)

	// Concurrent updates
	done := make(chan bool, 100)
	for i := 0; i < 100; i++ {
		go func(iteration int) {
			sandboxCopy := *sandbox
			sandboxCopy.Name = fmt.Sprintf("updated-%d", iteration)
			sandboxCopy.LastActivityAt = time.Now().UTC()
			_ = store.UpdateSandbox(ctx, &sandboxCopy)
			done <- true
		}(i)
	}

	// Wait for all goroutines
	for i := 0; i < 100; i++ {
		<-done
	}

	// Verify session still exists
	retrieved, err := store.GetSandboxBySessionID(ctx, "concurrent-valkey")
	require.NoError(t, err)
	assert.Equal(t, "concurrent-valkey", retrieved.SessionID)
}

