package router

import (
	"context"
	"fmt"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

// SessionManager handles session resolution and management.
type SessionManager struct {
	store           SessionStore
	workloadManager string
	client          *http.Client
}

// SessionStore defines the interface for session storage.
type SessionStore interface {
	GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error)
}

// SandboxInfo represents sandbox session information.
type SandboxInfo struct {
	SessionID      string
	Namespace      string
	Name           string
	Kind           string
	PodIP          string
	EntryPoints    []EntryPoint
	LastActivityAt time.Time
}

// EntryPoint represents a service endpoint.
type EntryPoint struct {
	Port       int
	Protocol   string
	PathPrefix string
}

// NewSessionManager creates a new session manager.
func NewSessionManager(store SessionStore, workloadManagerURL string) *SessionManager {
	return &SessionManager{
		store:           store,
		workloadManager: workloadManagerURL,
		client: &http.Client{
			Timeout: 30 * time.Second,
		},
	}
}

// ResolveSession resolves a session from the header or creates a new one.
func (sm *SessionManager) ResolveSession(ctx context.Context, namespace, name, kind string, sessionID string) (*SandboxInfo, error) {
	// If session ID provided, try to load from store
	if sessionID != "" {
		sandbox, err := sm.store.GetSandboxBySessionID(ctx, sessionID)
		if err == nil {
			return sandbox, nil
		}
		// Session not found or error, continue to create new
	}

	// Create new session via workload manager
	return sm.createSession(ctx, namespace, name, kind)
}

// createSession creates a new session via the workload manager.
func (sm *SessionManager) createSession(ctx context.Context, namespace, name, kind string) (*SandboxInfo, error) {
	// In real implementation, this would make an HTTP call to workload manager
	// For now, return a placeholder
	return &SandboxInfo{
		SessionID:      fmt.Sprintf("%s-%s-%d", namespace, name, time.Now().Unix()),
		Namespace:      namespace,
		Name:           name,
		Kind:           kind,
		PodIP:          "10.0.0.1",
		EntryPoints:    []EntryPoint{{Port: 8080, Protocol: "HTTP", PathPrefix: "/"}},
		LastActivityAt: time.Now(),
	}, nil
}

// ProxyHandler handles reverse proxying to sandboxes.
type ProxyHandler struct {
	sessionManager *SessionManager
	transport      http.RoundTripper
}

// NewProxyHandler creates a new proxy handler.
func NewProxyHandler(sm *SessionManager) *ProxyHandler {
	return &ProxyHandler{
		sessionManager: sm,
		transport:      &http.Transport{
			MaxIdleConns:        100,
			MaxIdleConnsPerHost: 10,
			IdleConnTimeout:     90 * time.Second,
		},
	}
}

// HandleProxy handles proxy requests to sandboxes.
func (ph *ProxyHandler) HandleProxy(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	kind := c.Param("kind")
	path := c.Param("path")

	// Get session ID from header
	sessionID := c.GetHeader("X-AgentCube-Session-ID")

	// Resolve session
	ctx := c.Request.Context()
	sandbox, err := ph.sessionManager.ResolveSession(ctx, namespace, name, kind, sessionID)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to resolve session"})
		return
	}

	// Find matching entry point
	entryPoint := ph.findEntryPoint(sandbox, path)
	if entryPoint == nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "no matching entry point"})
		return
	}

	// Build target URL
	targetURL := ph.buildTargetURL(sandbox, entryPoint, path)

	// Create reverse proxy
	proxy := httputil.NewSingleHostReverseProxy(targetURL)
	proxy.Transport = ph.transport

	// Modify request director
	originalDirector := proxy.Director
	proxy.Director = func(req *http.Request) {
		originalDirector(req)

		// Update forwarding headers
		req.Header.Set("X-Forwarded-Host", req.Host)
		req.Header.Set("X-Forwarded-Proto", "http")

		if clientIP := c.ClientIP(); clientIP != "" {
			req.Header.Set("X-Forwarded-For", clientIP)
		}

		// Inject JWT for sandbox/sandboxclaim kinds
		if sandbox.Kind == "Sandbox" || sandbox.Kind == "SandboxClaim" {
			token, err := generateJWT(sandbox.SessionID)
			if err == nil {
				req.Header.Set("Authorization", "Bearer "+token)
			}
		}
	}

	// Set session ID in response header
	c.Writer.Header().Set("X-AgentCube-Session-ID", sandbox.SessionID)

	// Update activity (non-blocking)
	go ph.updateActivity(sandbox.SessionID)

	// Serve the request
	proxy.ServeHTTP(c.Writer, c.Request)
}

// findEntryPoint finds the matching entry point for a path.
func (ph *ProxyHandler) findEntryPoint(sandbox *SandboxInfo, path string) *EntryPoint {
	for _, ep := range sandbox.EntryPoints {
		if strings.HasPrefix(path, ep.PathPrefix) {
			return &ep
		}
	}
	// Return first entry point if no match
	if len(sandbox.EntryPoints) > 0 {
		return &sandbox.EntryPoints[0]
	}
	return nil
}

// buildTargetURL builds the target URL for the proxy.
func (ph *ProxyHandler) buildTargetURL(sandbox *SandboxInfo, ep *EntryPoint, path string) *url.URL {
	scheme := "http"
	if ep.Protocol == "HTTPS" {
		scheme = "https"
	}

	target := &url.URL{
		Scheme: scheme,
		Host:   fmt.Sprintf("%s:%d", sandbox.PodIP, ep.Port),
		Path:   path,
	}

	return target
}

// updateActivity updates the last activity timestamp.
func (ph *ProxyHandler) updateActivity(sessionID string) {
	// In real implementation, this would update the store
	// For now, just log
	_ = sessionID
}

// generateJWT generates a JWT token for sandbox authentication.
func generateJWT(sessionID string) (string, error) {
	token := jwt.NewWithClaims(jwt.SigningMethodHS256, jwt.MapClaims{
		"session_id": sessionID,
		"exp":        time.Now().Add(time.Hour).Unix(),
	})

	// In real implementation, use proper signing key
	return token.SignedString([]byte("secret-key"))
}

// AuthMiddleware validates Bearer tokens.
type AuthMiddleware struct {
	publicKey string
	cache     *TokenCache
}

// TokenCache provides LRU caching for token validation.
type TokenCache struct {
	mu       sync.RWMutex
	tokens   map[string]tokenEntry
	maxSize  int
	ttl      time.Duration
}

type tokenEntry struct {
	valid      bool
	expiresAt  time.Time
}

// NewAuthMiddleware creates a new auth middleware.
func NewAuthMiddleware(publicKey string) *AuthMiddleware {
	return &AuthMiddleware{
		publicKey: publicKey,
		cache: &TokenCache{
			tokens:  make(map[string]tokenEntry),
			maxSize: 1000,
			ttl:     5 * time.Minute,
		},
	}
}

// Middleware returns the Gin middleware function.
func (am *AuthMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		// Skip auth for health endpoints
		if strings.HasPrefix(c.Request.URL.Path, "/health") {
			c.Next()
			return
		}

		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
			return
		}

		parts := strings.SplitN(authHeader, " ", 2)
		if len(parts) != 2 || strings.ToLower(parts[0]) != "bearer" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid authorization header"})
			return
		}

		token := parts[1]

		// Check cache
		if am.isCached(token) {
			c.Next()
			return
		}

		// Validate token
		if !am.validateToken(token) {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			return
		}

		// Cache the valid token
		am.cacheToken(token)
		c.Next()
	}
}

// isCached checks if a token is in the cache.
func (am *AuthMiddleware) isCached(token string) bool {
	am.cache.mu.RLock()
	entry, exists := am.cache.tokens[token]
	am.cache.mu.RUnlock()

	if !exists {
		return false
	}

	if time.Now().After(entry.expiresAt) {
		// Expired, remove from cache
		am.cache.mu.Lock()
		delete(am.cache.tokens, token)
		am.cache.mu.Unlock()
		return false
	}

	return entry.valid
}

// cacheToken caches a valid token.
func (am *AuthMiddleware) cacheToken(token string) {
	am.cache.mu.Lock()

	// Clean up expired entries if cache is full
	if len(am.cache.tokens) >= am.cache.maxSize {
		now := time.Now()
		for t, entry := range am.cache.tokens {
			if now.After(entry.expiresAt) {
				delete(am.cache.tokens, t)
			}
		}
	}

	am.cache.tokens[token] = tokenEntry{
		valid:     true,
		expiresAt: time.Now().Add(am.cache.ttl),
	}
	am.cache.mu.Unlock()
}

// validateToken validates a JWT token.
func (am *AuthMiddleware) validateToken(tokenString string) bool {
	// In real implementation, parse and validate JWT with public key
	// For now, simple validation
	token, _, err := new(jwt.Parser).ParseUnverified(tokenString, jwt.MapClaims{})
	if err != nil {
		return false
	}

	if claims, ok := token.Claims.(jwt.MapClaims); ok {
		if exp, ok := claims["exp"].(float64); ok {
			return time.Now().Unix() < int64(exp)
		}
	}

	return false
}

// ConcurrencyMiddleware limits concurrent requests.
type ConcurrencyMiddleware struct {
	semaphore chan struct{}
}

// NewConcurrencyMiddleware creates a new concurrency limiter.
func NewConcurrencyMiddleware(maxConcurrent int) *ConcurrencyMiddleware {
	if maxConcurrent <= 0 {
		maxConcurrent = 1000
	}
	return &ConcurrencyMiddleware{
		tmaphore: make(chan struct{}, maxConcurrent),
	}
}

// Middleware returns the Gin middleware function.
func (cm *ConcurrencyMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		// Try to acquire semaphore
		select {
		case cm.semaphore <- struct{}{}:
			defer func() {
				// Release semaphore when done
				select {
				case <-cm.semaphore:
				default:
				}
			}()
			c.Next()
		default:
			// Semaphore full, return 429
			c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
				"error": "too many concurrent requests",
			})
		}
	}
}

// ErrorHandler maps errors to appropriate HTTP status codes.
type ErrorHandler struct{}

// Handle handles proxy errors and maps them to HTTP status codes.
func (eh *ErrorHandler) Handle(c *gin.Context, err error) {
	if err == nil {
		return
	}

	errStr := err.Error()

	// Connection refused
	if strings.Contains(errStr, "connection refused") {
		c.AbortWithStatusJSON(http.StatusBadGateway, gin.H{
			"error": "sandbox unreachable",
		})
		return
	}

	// Timeout
	if strings.Contains(errStr, "timeout") {
		c.AbortWithStatusJSON(http.StatusGatewayTimeout, gin.H{
			"error": "sandbox timeout",
		})
		return
	}

	// Generic error
	c.AbortWithStatusJSON(http.StatusInternalServerError, gin.H{
		"error": "internal server error",
	})
}

