package main

import (
	"context"
	"crypto/rsa"
	"crypto/x509"
	"encoding/base64"
	"encoding/json"
	"encoding/pem"
	"fmt"
	"io"
	"net/http"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

const (
	defaultPort      = "8080"
	defaultTimeout   = 60 * time.Second
	maxBodySize      = 100 * 1024 * 1024 // 100MB
)

var (
	workspaceDir string
	publicKey    *rsa.PublicKey
)

func main() {
	port := os.Getenv("PORT")
	if port == "" {
		port = defaultPort
	}

	workspaceDir = os.Getenv("PICOD_WORKSPACE")
	if workspaceDir == "" {
		var err error
		workspaceDir, err = os.Getwd()
		if err != nil {
			fmt.Fprintf(os.Stderr, "Failed to get working directory: %v\n", err)
			os.Exit(1)
		}
	}

	// Load public key for JWT validation
	if err := loadPublicKey(); err != nil {
		fmt.Fprintf(os.Stderr, "Failed to load public key: %v\n", err)
		os.Exit(1)
	}

	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Recovery())

	// Health endpoint (no auth)
	router.GET("/health", handleHealth)

	// API routes (with auth)
	api := router.Group("/api")
	api.Use(authMiddleware())
	{
		api.POST("/execute", handleExecute)
		api.POST("/files", handleFileUpload)
		api.GET("/files", handleFileList)
		api.GET("/files/*path", handleFileDownload)
	}

	srv := &http.Server{
		Addr:              ":" + port,
		Handler:           router,
		ReadHeaderTimeout: 10 * time.Second,
	}

	fmt.Printf("PicoD server starting on port %s\n", port)
	fmt.Printf("Workspace: %s\n", workspaceDir)
	if err := srv.ListenAndServe(); err != nil {
		fmt.Fprintf(os.Stderr, "Server error: %v\n", err)
		os.Exit(1)
	}
}

func loadPublicKey() error {
	keyData := os.Getenv("PICOD_AUTH_PUBLIC_KEY")
	if keyData == "" {
		// No auth required
		return nil
	}

	// Decode base64 if needed
	decoded, err := base64.StdEncoding.DecodeString(keyData)
	if err != nil {
		// Try as plain PEM
		decoded = []byte(keyData)
	}

	block, _ := pem.Decode(decoded)
	if block == nil {
		return fmt.Errorf("failed to decode PEM block")
	}

	pub, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	var ok bool
	publicKey, ok = pub.(*rsa.PublicKey)
	if !ok {
		return fmt.Errorf("not an RSA public key")
	}

	return nil
}

func authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		if publicKey == nil {
			// No auth configured
			c.Next()
			return
		}

		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
			return
		}

		parts := strings.SplitN(authHeader, " ", 2)
		if len(parts) != 2 || strings.ToLower(parts[0]) != "bearer" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid authorization header"})
			return
		}

		tokenString := parts[1]
		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
			}
			return publicKey, nil
		})

		if err != nil || !token.Valid {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			return
		}

		c.Next()
	}
}

func handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

// ExecuteRequest represents a code execution request.
type ExecuteRequest struct {
	Command     string            `json:"command" binding:"required"`
	Timeout     int               `json:"timeout"`
	Environment map[string]string `json:"environment,omitempty"`
	WorkDir     string            `json:"work_dir,omitempty"`
}

// ExecuteResponse represents a code execution response.
type ExecuteResponse struct {
	Stdout   string `json:"stdout"`
	Stderr   string `json:"stderr"`
	ExitCode int    `json:"exit_code"`
}

func handleExecute(c *gin.Context) {
	// Limit request body size
	c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, maxBodySize)

	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	timeout := defaultTimeout
	if req.Timeout > 0 {
		timeout = time.Duration(req.Timeout) * time.Second
	}

	workDir := workspaceDir
	if req.WorkDir != "" {
		sanitized := sanitizePath(req.WorkDir)
		if !isPathSafe(sanitized) {
			c.JSON(http.StatusBadRequest, gin.H{"error": "invalid work directory"})
			return
		}
		workDir = sanitized
	}

	ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
	defer cancel()

	cmd := exec.CommandContext(ctx, "sh", "-c", req.Command)
	cmd.Dir = workDir
	cmd.Env = os.Environ()

	// Add custom environment variables
	for k, v := range req.Environment {
		cmd.Env = append(cmd.Env, fmt.Sprintf("%s=%s", k, v))
	}

	stdout, err := cmd.Output()
	var stderr []byte
	var exitCode int

	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			stderr = exitErr.Stderr
			exitCode = exitErr.ExitCode()
		} else if ctx.Err() == context.DeadlineExceeded {
			exitCode = 124 // Timeout exit code
			stderr = []byte("command timed out")
		} else {
			exitCode = 1
			stderr = []byte(err.Error())
		}
	}

	c.JSON(http.StatusOK, ExecuteResponse{
		Stdout:   string(stdout),
		Stderr:   string(stderr),
		ExitCode: exitCode,
	})
}

// FileUploadRequest represents a file upload request.
type FileUploadRequest struct {
	Path    string `json:"path" binding:"required"`
	Content string `json:"content" binding:"required"`
	Mode    string `json:"mode,omitempty"`
}

func handleFileUpload(c *gin.Context) {
	contentType := c.ContentType()

	if contentType == "multipart/form-data" {
		handleMultipartUpload(c)
		return
	}

	// Handle JSON base64 upload
	c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, maxBodySize)

	var req FileUploadRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	sanitizedPath := sanitizePath(req.Path)
	if !isPathSafe(sanitizedPath) {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid path"})
		return
	}

	// Decode base64 content
	content, err := base64.StdEncoding.DecodeString(req.Content)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid base64 content"})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to create directory"})
		return
	}

	if err := os.WriteFile(sanitizedPath, content, 0644); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to write file"})
		return
	}

	// Set custom mode if provided
	if req.Mode != "" {
		mode, err := strconv.ParseUint(req.Mode, 8, 32)
		if err == nil {
			os.Chmod(sanitizedPath, os.FileMode(mode))
		}
	}

	c.JSON(http.StatusOK, gin.H{"status": "uploaded"})
}

func handleMultipartUpload(c *gin.Context) {
	file, header, err := c.Request.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "failed to get file"})
		return
	}
	defer file.Close()

	path := c.PostForm("path")
	if path == "" {
		path = header.Filename
	}

	sanitizedPath := sanitizePath(filepath.Join(workspaceDir, path))
	if !isPathSafe(sanitizedPath) {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid path"})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to create directory"})
		return
	}

	out, err := os.Create(sanitizedPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to create file"})
		return
	}
	defer out.Close()

	if _, err := io.Copy(out, file); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to write file"})
		return
	}

	// Set mode if provided
	if modeStr := c.PostForm("mode"); modeStr != "" {
		mode, err := strconv.ParseUint(modeStr, 8, 32)
		if err == nil {
			os.Chmod(sanitizedPath, os.FileMode(mode))
		}
	}

	c.JSON(http.StatusOK, gin.H{"status": "uploaded", "path": path})
}

// FileInfo represents file metadata.
type FileInfo struct {
	Name    string    `json:"name"`
	Size    int64     `json:"size"`
	Mode    string    `json:"mode"`
	ModTime time.Time `json:"mod_time"`
	IsDir   bool      `json:"is_dir"`
}

func handleFileList(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		path = "."
	}

	sanitizedPath := sanitizePath(filepath.Join(workspaceDir, path))
	if !isPathSafe(sanitizedPath) {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid path"})
		return
	}

	entries, err := os.ReadDir(sanitizedPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to read directory"})
		return
	}

	var files []FileInfo
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}

		files = append(files, FileInfo{
			Name:    entry.Name(),
			Size:    info.Size(),
			Mode:    info.Mode().String(),
			ModTime: info.ModTime(),
			IsDir:   entry.IsDir(),
		})
	}

	c.JSON(http.StatusOK, gin.H{"files": files})
}

func handleFileDownload(c *gin.Context) {
	path := c.Param("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "missing path"})
		return
	}

	sanitizedPath := sanitizePath(filepath.Join(workspaceDir, path))
	if !isPathSafe(sanitizedPath) {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid path"})
		return
	}

	info, err := os.Stat(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{"error": "file not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to stat file"})
		return
	}

	if info.IsDir() {
		c.JSON(http.StatusBadRequest, gin.H{"error": "path is a directory"})
		return
	}

	c.File(sanitizedPath)
}

// sanitizePath cleans and returns an absolute path.
func sanitizePath(path string) string {
	path = filepath.Clean(path)
	if !filepath.IsAbs(path) {
		path = filepath.Join(workspaceDir, path)
	}
	return path
}

// isPathSafe checks if the path is within the workspace directory.
func isPathSafe(path string) bool {
	absPath, err := filepath.Abs(path)
	if err != nil {
		return false
	}

	absWorkspace, err := filepath.Abs(workspaceDir)
	if err != nil {
		return false
	}

	// Check if path is within workspace (handles symlinks)
	rel, err := filepath.Rel(absWorkspace, absPath)
	if err != nil {
		return false
	}

	return !strings.HasPrefix(rel, "..")
}

package controllers

import (
	"context"
	"encoding/json"
	"fmt"
	"time"

	"github.com/google/uuid"
	"k8s.io/apimachinery/pkg/runtime"
)

// SandboxController manages sandbox lifecycle operations.
type SandboxController struct {
	store        SessionStore
	k8sClient    KubernetesClient
	garbageCollector *GarbageCollector
}

// SessionStore defines the interface for session storage.
type SessionStore interface {
	GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error)
	StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error
	UpdateSandbox(ctx context.Context, sandbox *SandboxInfo) error
	DeleteSandboxBySessionID(ctx context.Context, sessionID string) error
	ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error)
	ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error)
}

// KubernetesClient defines the interface for K8s operations.
type KubernetesClient interface {
	CreateSandbox(ctx context.Context, spec *SandboxSpec) error
	DeleteSandbox(ctx context.Context, namespace, name string) error
	GetPodStatus(ctx context.Context, namespace, name string) (*PodStatus, error)
	GetPodIP(ctx context.Context, namespace, name string) (string, error)
}

// SandboxInfo represents a sandbox session.
type SandboxInfo struct {
	SessionID        string            `json:"session_id"`
	Namespace        string            `json:"namespace"`
	Name             string            `json:"name"`
	Kind             string            `json:"kind"`
	PodIP            string            `json:"pod_ip"`
	EntryPoints      []EntryPoint      `json:"entry_points"`
	ExpiresAt        time.Time         `json:"expires_at"`
	LastActivityAt   time.Time         `json:"last_activity_at"`
	CreatedAt        time.Time         `json:"created_at"`
	Status           string            `json:"status"`
	Labels           map[string]string `json:"labels,omitempty"`
	Annotations      map[string]string `json:"annotations,omitempty"`
}

// EntryPoint represents a sandbox service endpoint.
type EntryPoint struct {
	Port       int    `json:"port"`
	Protocol   string `json:"protocol"`
	PathPrefix string `json:"path_prefix"`
}

// SandboxSpec represents sandbox creation specification.
type SandboxSpec struct {
	Namespace      string
	Name           string
	Kind           string
	PodTemplate    *PodTemplate
	SessionTimeout time.Duration
	MaxDuration    time.Duration
}

// PodTemplate represents pod template.
type PodTemplate struct {
	Containers []Container
}

// Container represents a container specification.
type Container struct {
	Name  string `json:"name"`
	Image string `json:"image"`
	Ports []Port `json:"ports,omitempty"`
}

// Port represents a port specification.
type Port struct {
	Port     int    `json:"port"`
	Protocol string `json:"protocol"`
}

// PodStatus represents pod status.
type PodStatus struct {
	Phase   string
	Ready   bool
	Message string
}

// CreateSandboxRequest represents a sandbox creation request.
type CreateSandboxRequest struct {
	Namespace      string            `json:"namespace"`
	Name           string            `json:"name"`
	Kind           string            `json:"kind"`
	PodTemplate    *PodTemplate      `json:"pod_template"`
	SessionTimeout time.Duration     `json:"session_timeout"`
	MaxDuration    time.Duration     `json:"max_duration"`
	Labels         map[string]string `json:"labels,omitempty"`
	Annotations    map[string]string `json:"annotations,omitempty"`
}

// CreateSandboxResponse represents a sandbox creation response.
type CreateSandboxResponse struct {
	SessionID  string   `json:"session_id"`
	Endpoint   string   `json:"endpoint"`
	EntryPoints []EntryPoint `json:"entry_points"`
	Status     string   `json:"status"`
}

// NewSandboxController creates a new sandbox controller.
func NewSandboxController(store SessionStore, k8sClient KubernetesClient) *SandboxController {
	return &SandboxController{
		store:     store,
		k8sClient: k8sClient,
		garbageCollector: &GarbageCollector{
			store:      store,
			k8sClient:  k8sClient,
			tickPeriod: 15 * time.Second,
			batchLimit: 16,
		},
	}
}

// CreateSandbox creates a new sandbox session.
func (sc *SandboxController) CreateSandbox(ctx context.Context, req *CreateSandboxRequest) (*CreateSandboxResponse, error) {
	// Generate session ID
	sessionID := uuid.New().String()

	// Check for existing session with same name
	// In real implementation, query store by name

	// Calculate expiration
	sessionTimeout := req.SessionTimeout
	if sessionTimeout == 0 {
		sessionTimeout = 15 * time.Minute
	}

	maxDuration := req.MaxDuration
	if maxDuration == 0 {
		maxDuration = 8 * time.Hour
	}

	expiresAt := time.Now().Add(maxDuration)

	// Store placeholder before CR creation
	sandbox := &SandboxInfo{
		SessionID:      sessionID,
		Namespace:      req.Namespace,
		Name:           req.Name,
		Kind:           req.Kind,
		ExpiresAt:      expiresAt,
		LastActivityAt: time.Now(),
		CreatedAt:      time.Now(),
		Status:         "Pending",
		Labels:         req.Labels,
		Annotations:    req.Annotations,
	}

	if err := sc.store.StoreSandbox(ctx, sandbox); err != nil {
		return nil, fmt.Errorf("failed to store placeholder: %w", err)
	}

	// Create K8s sandbox resource
	spec := &SandboxSpec{
		Namespace:      req.Namespace,
		Name:           req.Name,
		Kind:           req.Kind,
		PodTemplate:    req.PodTemplate,
		SessionTimeout: sessionTimeout,
		MaxDuration:    maxDuration,
	}

	if err := sc.k8sClient.CreateSandbox(ctx, spec); err != nil {
		// Rollback on failure
		sc.store.DeleteSandboxBySessionID(ctx, sessionID)
		return nil, fmt.Errorf("failed to create sandbox: %w", err)
	}

	// Wait for pod to be running (2 minute timeout)
	ctx, cancel := context.WithTimeout(ctx, 2*time.Minute)
	defer cancel()

	ticker := time.NewTicker(2 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			sc.store.DeleteSandboxBySessionID(ctx, sessionID)
			return nil, fmt.Errorf("timeout waiting for sandbox to be ready")
		case <-ticker.C:
			status, err := sc.k8sClient.GetPodStatus(ctx, req.Namespace, req.Name)
			if err != nil {
				continue
			}

			if status.Phase == "Running" && status.Ready {
				// Get Pod IP
				podIP, err := sc.k8sClient.GetPodIP(ctx, req.Namespace, req.Name)
				if err != nil {
					continue
				}

				// Update sandbox with Pod IP and entry points
				sandbox.PodIP = podIP
				sandbox.Status = "Running"

				// Build entry points from pod template
				if req.PodTemplate != nil {
					for _, container := range req.PodTemplate.Containers {
						for _, port := range container.Ports {
							prefix := "/"
							if req.Kind == "CodeInterpreter" {
								prefix = "/api"
							}
							sandbox.EntryPoints = append(sandbox.EntryPoints, EntryPoint{
								Port:       port.Port,
								Protocol:   port.Protocol,
								PathPrefix: prefix,
							})
						}
					}
				}

				if err := sc.store.UpdateSandbox(ctx, sandbox); err != nil {
					return nil, fmt.Errorf("failed to update sandbox: %w", err)
				}

				// Build endpoint
				endpoint := fmt.Sprintf("http://%s", podIP)
				if len(sandbox.EntryPoints) > 0 {
					endpoint = fmt.Sprintf("%s:%d", endpoint, sandbox.EntryPoints[0].Port)
				}

				return &CreateSandboxResponse{
					SessionID:   sessionID,
					Endpoint:    endpoint,
					EntryPoints: sandbox.EntryPoints,
					Status:      "Running",
				}, nil
			}

			if status.Phase == "Failed" {
				sc.store.DeleteSandboxBySessionID(ctx, sessionID)
				return nil, fmt.Errorf("sandbox failed to start: %s", status.Message)
			}
		}
	}
}

// DeleteSandbox deletes a sandbox session.
func (sc *SandboxController) DeleteSandbox(ctx context.Context, sessionID string) error {
	// Get sandbox info
	sandbox, err := sc.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		return fmt.Errorf("failed to get sandbox: %w", err)
	}

	// Delete K8s resource
	if err := sc.k8sClient.DeleteSandbox(ctx, sandbox.Namespace, sandbox.Name); err != nil {
		// Continue to delete from store even if K8s delete fails
		// Log error but don't return
	}

	// Delete from store
	if err := sc.store.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		return fmt.Errorf("failed to delete sandbox from store: %w", err)
	}

	return nil
}

// StartGarbageCollector starts the garbage collection loop.
func (sc *SandboxController) StartGarbageCollector(ctx context.Context) {
	sc.garbageCollector.Start(ctx)
}

// StopGarbageCollector stops the garbage collection loop.
func (sc *SandboxController) StopGarbageCollector() {
	sc.garbageCollector.Stop()
}

