package controllers

import (
	"context"
	"sync"
	"time"

	"k8s.io/klog/v2"
)

// GarbageCollector periodically cleans up expired and inactive sandboxes.
type GarbageCollector struct {
	store      SessionStore
	k8sClient  KubernetesClient
	tickPeriod time.Duration
	batchLimit int
	stopCh     chan struct{}
	wg         sync.WaitGroup
}

// NewGarbageCollector creates a new garbage collector.
func NewGarbageCollector(store SessionStore, k8sClient KubernetesClient) *GarbageCollector {
	return &GarbageCollector{
		store:      store,
		k8sClient:  k8sClient,
		tickPeriod: 15 * time.Second,
		batchLimit: 16,
		stopCh:     make(chan struct{}),
	}
}

// Start begins the garbage collection loop.
func (gc *GarbageCollector) Start(ctx context.Context) {
	gc.wg.Add(1)
	go gc.run(ctx)
}

// Stop stops the garbage collection loop.
func (gc *GarbageCollector) Stop() {
	close(gc.stopCh)
	gc.wg.Wait()
}

func (gc *GarbageCollector) run(ctx context.Context) {
	defer gc.wg.Done()

	ticker := time.NewTicker(gc.tickPeriod)
	defer ticker.Stop()

	// Run immediately on start
	gc.collect(ctx)

	for {
		select {
		case <-ctx.Done():
			klog.Info("Garbage collector stopped: context cancelled")
			return
		case <-gc.stopCh:
			klog.Info("Garbage collector stopped: stop signal received")
			return
		case <-ticker.C:
			gc.collect(ctx)
		}
	}
}

func (gc *GarbageCollector) collect(ctx context.Context) {
	now := time.Now()

	// Collect expired sandboxes
	if err := gc.collectExpired(ctx, now); err != nil {
		klog.Errorf("Failed to collect expired sandboxes: %v", err)
	}

	// Collect inactive sandboxes (inactive > 15 minutes)
	if err := gc.collectInactive(ctx, now); err != nil {
		klog.Errorf("Failed to collect inactive sandboxes: %v", err)
	}
}

func (gc *GarbageCollector) collectExpired(ctx context.Context, now time.Time) error {
	expiredSessions, err := gc.store.ListExpiredSandboxes(ctx, now, gc.batchLimit)
	if err != nil {
		return err
	}

	for _, sessionID := range expiredSessions {
		if err := gc.deleteSandbox(ctx, sessionID); err != nil {
			klog.Warningf("Failed to delete expired sandbox %s: %v", sessionID, err)
		} else {
			klog.Infof("Deleted expired sandbox: %s", sessionID)
		}
	}

	return nil
}

func (gc *GarbageCollector) collectInactive(ctx context.Context, now time.Time) error {
	// Sessions inactive for more than 15 minutes
	inactiveThreshold := now.Add(-15 * time.Minute)

	inactiveSessions, err := gc.store.ListInactiveSandboxes(ctx, inactiveThreshold, gc.batchLimit)
	if err != nil {
		return err
	}

	for _, sessionID := range inactiveSessions {
		if err := gc.deleteSandbox(ctx, sessionID); err != nil {
			klog.Warningf("Failed to delete inactive sandbox %s: %v", sessionID, err)
		} else {
			klog.Infof("Deleted inactive sandbox: %s", sessionID)
		}
	}

	return nil
}

func (gc *GarbageCollector) deleteSandbox(ctx context.Context, sessionID string) error {
	// Get sandbox info
	sandbox, err := gc.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		// Sandbox already deleted from store, clean up orphan
		return nil
	}

	// Delete K8s resource (ignore errors)
	if err := gc.k8sClient.DeleteSandbox(ctx, sandbox.Namespace, sandbox.Name); err != nil {
		klog.Warningf("Failed to delete K8s sandbox %s/%s: %v", sandbox.Namespace, sandbox.Name, err)
	}

	// Delete from store
	if err := gc.store.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		return err
	}

	return nil
}

