    workspace: str = workspace_opt,
    agent_name: Optional[str] = typer.Option(None, "--agent-name", help="Override agent name"),
    language: Optional[str] = typer.Option(None, "--language", help="Language (python/java)"),
    entrypoint: Optional[str] = typer.Option(None, "--entrypoint", help="Entry command"),
    port: Optional[int] = typer.Option(None, "--port", help="Container port"),
    build_mode: Optional[str] = typer.Option(None, "--build-mode", help="Build mode (local/docker/cloud)"),
    description: Optional[str] = typer.Option(None, "--description", help="Description"),
    output: Optional[str] = typer.Option(None, "-o", "--output", help="Output file"),
    verbose: bool = verbose_opt,
):
    """Validate and package workspace."""
    console.print(f"[bold blue]Packing workspace:[/bold blue] {workspace}")

    # Load existing metadata or create new
    metadata = load_metadata(workspace)

    # Apply CLI overrides
    if agent_name:
        metadata["name"] = agent_name
    if language:
        metadata["language"] = language
    if entrypoint:
        metadata["entrypoint"] = entrypoint
    if port:
        metadata["port"] = port
    if build_mode:
        metadata["build_mode"] = build_mode
    if description:
        metadata["description"] = description

    # Validate workspace structure
    if not validate_workspace(workspace, metadata):
        console.print("[bold red]Validation failed[/bold red]")
        raise typer.Exit(1)

    # Save metadata
    output_path = output or os.path.join(workspace, "agent_metadata.yaml")
    save_metadata(metadata, output_path)

    console.print(f"[bold green]✓[/bold green] Package created: {output_path}")


@app.command()
def build(
    workspace: str = workspace_opt,
    proxy: Optional[str] = typer.Option(None, "-p", "--proxy", help="HTTP proxy"),
    cloud_provider: Optional[str] = typer.Option(None, "--cloud-provider", help="Cloud provider"),
    output: Optional[str] = typer.Option(None, "-o", "--output", help="Output file"),
    verbose: bool = verbose_opt,
):
    """Build container image."""
    console.print(f"[bold blue]Building workspace:[/bold blue] {workspace}")

    metadata = load_metadata(workspace)
    if not metadata:
        console.print("[bold red]Error:[/bold red] No metadata found. Run 'agentcube pack' first.")
        raise typer.Exit(1)

    # Bump version
    old_version = metadata.get("version", "0.0.0")
    new_version = bump_version(old_version)
    metadata["version"] = new_version

    console.print(f"[dim]Version: {old_version} → {new_version}[/dim]")

    try:
        # Build image
        build_image(workspace, metadata, proxy, verbose)
        console.print(f"[bold green]✓[/bold green] Build successful: {metadata['name']}:{new_version}")

        # Save metadata with new version
        save_metadata(metadata, os.path.join(workspace, "agent_metadata.yaml"))

    except Exception as e:
        console.print(f"[bold red]Build failed:[/bold red] {e}")
        # Revert version
        metadata["version"] = old_version
        save_metadata(metadata, os.path.join(workspace, "agent_metadata.yaml"))
        raise typer.Exit(1)


@app.command()
def publish(
    workspace: str = workspace_opt,
    version: Optional[str] = typer.Option(None, "--version", help="Override version"),
    image_url: Optional[str] = typer.Option(None, "--image-url", help="Pre-built image URL"),
    image_username: Optional[str] = typer.Option(None, "--image-username", help="Registry username"),
    image_password: Optional[str] = typer.Option(None, "--image-password", help="Registry password"),
    description: Optional[str] = typer.Option(None, "--description", help="Description"),
    region: Optional[str] = typer.Option(None, "--region", help="Cloud region"),
    cloud_provider: Optional[str] = typer.Option(None, "--cloud-provider", help="Cloud provider"),
    provider: str = typer.Option("agentcube", "--provider", help="Deployment provider"),
    node_port: Optional[int] = typer.Option(None, "--node-port", help="NodePort for k8s"),
    replicas: int = typer.Option(1, "--replicas", help="Replica count"),
    namespace: str = typer.Option("default", "--namespace", help="K8s namespace"),
    verbose: bool = verbose_opt,
):
    """Deploy agent."""
    console.print(f"[bold blue]Publishing workspace:[/bold blue] {workspace}")

    metadata = load_metadata(workspace)
    if not metadata:
        console.print("[bold red]Error:[/bold red] No metadata found. Run 'agentcube pack' first.")
        raise typer.Exit(1)

    if version:
        metadata["version"] = version
    if description:
        metadata["description"] = description

    console.print(f"[dim]Provider: {provider}[/dim]")
    console.print(f"[dim]Namespace: {namespace}[/dim]")
    console.print(f"[dim]Replicas: {replicas}[/dim]")

    try:
        if provider == "agentcube":
            publish_to_agentcube(metadata, namespace, verbose)
        elif provider == "k8s":
            publish_to_k8s(metadata, namespace, node_port, replicas, verbose)
        else:
            console.print(f"[bold red]Unknown provider:[/bold red] {provider}")
            raise typer.Exit(1)

        console.print(f"[bold green]✓[/bold green] Published successfully")

    except Exception as e:
        console.print(f"[bold red]Publish failed:[/bold red] {e}")
        raise typer.Exit(1)


@app.command()
def invoke(
    workspace: str = workspace_opt,
    payload: str = typer.Option("{}", "--payload", help="JSON payload"),
    header: List[str] = typer.Option([], "--header", help="Custom headers (KEY:VALUE)"),
    provider: str = typer.Option("agentcube", "--provider", help="Provider"),
    verbose: bool = verbose_opt,
):
    """Invoke agent."""
    console.print(f"[bold blue]Invoking agent from:[/bold blue] {workspace}")

    metadata = load_metadata(workspace)
    if not metadata:
        console.print("[bold red]Error:[/bold red] No metadata found.")
        raise typer.Exit(1)

    try:
        request_payload = json.loads(payload)
    except json.JSONDecodeError as e:
        console.print(f"[bold red]Invalid JSON payload:[/bold red] {e}")
        raise typer.Exit(1)

    # Parse headers
    headers = {}
    for h in header:
        if ":" not in h:
            console.print(f"[bold red]Invalid header format:[/bold red] {h}")
            raise typer.Exit(1)
        key, value = h.split(":", 1)
        headers[key.strip()] = value.strip()

    try:
        response = do_invoke(metadata, request_payload, headers, provider, verbose)
        console.print("[bold green]Response:[/bold green]")
        console.print_json(data=response)
    except Exception as e:
        console.print(f"[bold red]Invocation failed:[/bold red] {e}")
        raise typer.Exit(1)


