def load_metadata(workspace: str) -> Dict[str, Any]:
    """Load metadata from workspace."""
    metadata_file = os.path.join(workspace, "agent_metadata.yaml")
    if os.path.exists(metadata_file):
        import yaml
        with open(metadata_file, "r") as f:
            return yaml.safe_load(f) or {}
    return {}


def save_metadata(metadata: Dict[str, Any], path: str) -> None:
    """Save metadata to file."""
    import yaml
    with open(path, "w") as f:
        yaml.dump(metadata, f, default_flow_style=False)


def validate_workspace(workspace: str, metadata: Dict[str, Any]) -> bool:
    """Validate workspace structure."""
    # Check language-specific files
    language = metadata.get("language", "python")

    if language == "python":
        # Look for Python files
        py_files = list(Path(workspace).glob("*.py"))
        if not py_files:
            console.print("[yellow]Warning: No Python files found[/yellow]")
            return False
    elif language == "java":
        # Look for pom.xml or build.gradle
        if not os.path.exists(os.path.join(workspace, "pom.xml")):
            console.print("[yellow]Warning: No pom.xml found for Java project[/yellow]")
            return False

    return True


def bump_version(version: str) -> str:
    """Bump patch version."""
    parts = version.split(".")
    if len(parts) >= 3:
        parts[2] = str(int(parts[2]) + 1)
    else:
        parts.append("1")
    return ".".join(parts[:3])


def build_image(
    workspace: str,
    metadata: Dict[str, Any],
    proxy: Optional[str],
    verbose: bool
) -> None:
    """Build container image."""
    import docker

    client = docker.from_env()

    build_args = {}
    if proxy:
        build_args["HTTP_PROXY"] = proxy
        build_args["HTTPS_PROXY"] = proxy

    image_name = f"{metadata['name']}:{metadata['version']}"

    if verbose:
        console.print(f"[dim]Building image: {image_name}[/dim]")

    client.images.build(
        path=workspace,
        tag=image_name,
        buildargs=build_args,
    )


def publish_to_agentcube(
    metadata: Dict[str, Any],
    namespace: str,
    verbose: bool
) -> None:
    """Publish to AgentCube."""
    from agentcube import ControlPlaneClient

    client = ControlPlaneClient()

    try:
        response = client.create_sandbox(
            namespace=namespace,
            name=metadata["name"],
            kind="AgentRuntime",
            session_timeout=3600,
            max_duration=28800,
        )

        if verbose:
            console.print(f"[dim]Created AgentRuntime: {response['session_id']}[/dim]")
    finally:
        client.close()


def publish_to_k8s(
    metadata: Dict[str, Any],
    namespace: str,
    node_port: Optional[int],
    replicas: int,
    verbose: bool
) -> None:
    """Publish to Kubernetes."""
    # Create Deployment manifest
    deployment = {
        "apiVersion": "apps/v1",
        "kind": "Deployment",
        "metadata": {"name": metadata["name"], "namespace": namespace},
        "spec": {
            "replicas": replicas,
            "selector": {"matchLabels": {"app": metadata["name"]}},
            "template": {
                "metadata": {"labels": {"app": metadata["name"]}},
                "spec": {
                    "containers": [{
                        "name": "agent",
                        "image": f"{metadata['name']}:{metadata['version']}",
                        "ports": [{"containerPort": metadata.get("port", 8080)}],
                    }],
                },
            },
        },
    }

    # Create Service manifest
    service = {
        "apiVersion": "v1",
        "kind": "Service",
        "metadata": {"name": metadata["name"], "namespace": namespace},
        "spec": {
            "selector": {"app": metadata["name"]},
            "ports": [{"port": metadata.get("port", 8080)}],
            "type": "ClusterIP",
        },
    }

    if node_port:
        service["spec"]["type"] = "NodePort"
        service["spec"]["ports"][0]["nodePort"] = node_port

    if verbose:
        console.print("[dim]Applying Kubernetes manifests...[/dim]")

    # Apply manifests
    import subprocess

    for manifest in [deployment, service]:
        result = subprocess.run(
            ["kubectl", "apply", "-f", "-"],
            input=json.dumps(manifest),
            capture_output=True,
            text=True,
        )

        if result.returncode != 0:
            raise Exception(f"kubectl apply failed: {result.stderr}")


def do_invoke(
    metadata: Dict[str, Any],
    payload: Dict[str, Any],
    headers: Dict[str, str],
    provider: str,
    verbose: bool
) -> Dict[str, Any]:
    """Invoke agent."""
    from agentcube import AgentRuntimeClient

    router_url = os.getenv("ROUTER_URL", "http://localhost:8081")

    client = AgentRuntimeClient(
        router_url=router_url,
        namespace="default",
        agent_name=metadata["name"],
    )

    try:
        return client.invoke(payload)
    finally:
        client.close()


def get_status(
    metadata: Dict[str, Any],
    provider: str,
    verbose: bool
) -> Dict[str, Any]:
    """Get agent status."""
    status = {
        "name": metadata.get("name", "Unknown"),
        "version": metadata.get("version", "Unknown"),
        "status": "unknown",
    }

    if provider == "k8s":
        import subprocess

        result = subprocess.run(
            ["kubectl", "get", "deployment", metadata["name"], "-o", "json"],
            capture_output=True,
            text=True,
        )

        if result.returncode == 0:
            deployment = json.loads(result.stdout)
            ready = deployment.get("status", {}).get("readyReplicas", 0)
            total = deployment.get("status", {}).get("replicas", 0)
            status["status"] = "running" if ready == total and total > 0 else "pending"
            status["ready"] = f"{ready}/{total}"
        else:
            status["status"] = "not_published"

    return status


def main():
    """Main entry point."""
    app()


if __name__ == "__main__":
    main()

